def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    bg = int(grid[0][0])

    colors = set(int(x) for x in grid.flatten()) - {bg}

    output = grid.copy()

    for color in colors:
        cells = set()
        for r in range(H):
            for c in range(W):
                if grid[r][c] == color:
                    cells.add((r, c))

        if not cells:
            continue

        cols = [c for r, c in cells]
        rows = [r for r, c in cells]
        min_c, max_c = min(cols), max(cols)
        min_r, max_r = min(rows), max(rows)

        best_axis_2 = None
        best_axis_type = None
        best_preserved = -1

        # Try vertical axes
        for axis_2 in range(min_c * 2, max_c * 2 + 1):
            preserved = sum(1 for r, c in cells if (r, axis_2 - c) in cells)
            if preserved > best_preserved:
                best_preserved = preserved
                best_axis_2 = axis_2
                best_axis_type = 'vertical'

        # Try horizontal axes
        for axis_2 in range(min_r * 2, max_r * 2 + 1):
            preserved = sum(1 for r, c in cells if (axis_2 - r, c) in cells)
            if preserved > best_preserved:
                best_preserved = preserved
                best_axis_2 = axis_2
                best_axis_type = 'horizontal'

        # Remove non-preserved cells
        for r, c in cells:
            if best_axis_type == 'vertical':
                if (r, best_axis_2 - c) not in cells:
                    output[r][c] = bg
            else:
                if (best_axis_2 - r, c) not in cells:
                    output[r][c] = bg

    return output.tolist()

