    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape
    bg = int(grid[0][0])
    colors = set(int(x) for x in grid.flatten()) - {bg}

    shapes_data = {}
    has_tie = False

    for color in colors:
        cells = set((r, c) for r in range(H) for c in range(W) if grid[r][c] == color)
        if not cells:
            continue
        cols = [c for r, c in cells]
        best_preserved = -1
        best_axes = []

        for axis_2 in range(min(cols) * 2, max(cols) * 2 + 1):
            preserved = sum(1 for r, c in cells if (r, axis_2 - c) in cells)
            if preserved > best_preserved:
                best_preserved = preserved
                best_axes = [axis_2]
            elif preserved == best_preserved:
                best_axes.append(axis_2)

        shapes_data[color] = {'cells': cells, 'best_axes': best_axes}
        if len(best_axes) > 1:
            has_tie = True

    def build_output(axis_selector):
        out = grid.copy()
        for color, data in shapes_data.items():
            cells = data['cells']
            axis_2 = axis_selector(data['best_axes'])
            for r, c in cells:
                if (r, axis_2 - c) not in cells:
                    out[r][c] = bg
        return out.tolist()

    out1 = build_output(min)
    if not has_tie:
        return out1

    out2 = build_output(max)
    return [out1, out2]

